import java.util.regex.Pattern;
import java.util.stream.Collectors;

/**
 * A service to fetch and preview content from a given URL.
 * This is commonly used for generating link previews in applications.
 */
public class UrlPreviewService {

    // List of blocked protocols to prevent SSRF
    private static final List<String> BLOCKED_PROTOCOLS = Arrays.asList("file", "jar", "ftp");

    // List of blocked hosts/IPs to prevent internal access
    private static final List<String> BLOCKED_ADDRESSES = Arrays.asList(
        "localhost",
        "127.0.0.1",
        "0.0.0.0",
        "::1"
    );

    // Regular expression pattern to match IP addresses
    private static final Pattern IP_PATTERN = Pattern.compile(
        "^(([0-9]|[1-9][0-9]|1[0-9]{2}|2[0-4][0-9]|25[0-5])\\.){3}([0-9]|[1-9][0-9]|1[0-9]{2}|2[0-4][0-9]|25[0-5])$"
    );

    /**
     * Fetches the content from the provided URL string and returns a summary.
     * The summary is the first few lines of the resource content.
     *
     * @param urlString The URL of the resource to fetch.
     * @return A string containing a preview of the content, or an error message if fetching fails.
     */
    public String getUrlContentPreview(String urlString) {
        try {
            // Validate the URL to prevent SSRF attacks
            validateUrl(urlString);

            // Create a URL object from the user-provided string.
            URL url = new URL(urlString);

            // Check if the host resolves to a blocked address
            InetAddress[] addresses = InetAddress.getAllByName(url.getHost());
            for (InetAddress addr : addresses) {
                if (isAddressBlocked(addr)) {
                    throw new SecurityException("Access to internal/private addresses is not allowed");
                }
            }

            // Open a connection to the specified URL.
            URLConnection connection = url.openConnection();

            // Set security headers to prevent some server-side issues
            connection.setRequestProperty("User-Agent", "Mozilla/5.0 (compatible; ContentPreviewBot/1.0)");
            connection.setConnectTimeout(5000); // 5 seconds timeout
            connection.setReadTimeout(5000);    // 5 seconds timeout

            // Limit the response size to prevent large responses
            if (connection instanceof HttpURLConnection) {
                ((HttpURLConnection) connection).setRequestMethod("GET");
                int responseCode = ((HttpURLConnection) connection).getResponseCode();
                if (responseCode != HttpURLConnection.HTTP_OK) {
                    return "Error: HTTP " + responseCode + " received";
                }
            }

            // Read the content from the connection's input stream.
            try (InputStream inputStream = connection.getInputStream()) {
                // Limit the amount of data read to prevent large responses
                byte[] buffer = new byte[4096]; // Only read first 4KB
                int bytesRead = inputStream.read(buffer);

                if (bytesRead == -1) {
                    return "No content available";
                }

                String content = new String(buffer, 0, Math.max(0, bytesRead), StandardCharsets.UTF_8);

                // Return the first 5 lines as a preview.
                String[] lines = content.split("\\r?\\n");
                StringBuilder result = new StringBuilder();
                for (int i = 0; i < Math.min(5, lines.length); i++) {
                    if (i > 0) result.append("\n");
                    result.append(lines[i]);
                }
                return result.toString();
            }
        } catch (SecurityException se) {
            // Handle security-related exceptions specifically
            return "Security error: " + se.getMessage();
        } catch (Exception e) {
            // In case of any error, return a generic error message.
            return "Error fetching content from URL: " + e.getMessage();
        }
    }

    /**
     * Validates the URL to prevent common SSRF attack vectors
     */
    private void validateUrl(String urlString) throws MalformedURLException, SecurityException {
        URL url = new URL(urlString);

        // Block specific protocols that could be dangerous
        if (BLOCKED_PROTOCOLS.contains(url.getProtocol().toLowerCase())) {
            throw new SecurityException("Protocol not allowed: " + url.getProtocol());
        }

        // Block URLs with IP addresses in certain ranges (private/local networks)
        String host = url.getHost().toLowerCase();

        // Check for direct IP addresses using regex
        if (IP_PATTERN.matcher(host).matches()) {
            InetAddress addr;
            try {
                addr = InetAddress.getByName(host);
                if (isAddressBlocked(addr)) {
                    throw new SecurityException("Access to internal/private addresses is not allowed");
                }
            } catch (UnknownHostException e) {
                throw new SecurityException("Invalid host: " + host);
            }
        }

        // Block common internal hostnames
        for (String blockedAddr : BLOCKED_ADDRESSES) {
            if (host.equals(blockedAddr) || host.startsWith(blockedAddr + ".")) {
                throw new SecurityException("Access to internal/private addresses is not allowed");
            }
        }
    }

    /**
     * Checks if a string represents a valid IP address
     */
    private boolean isValidIpAddress(String ip) {
        return IP_PATTERN.matcher(ip).matches();
    }

    /**
     * Checks if an InetAddress is blocked (internal/private network)
     */
    private boolean isAddressBlocked(InetAddress addr) {
        String hostAddress = addr.getHostAddress();

        // Additional checks for private IP ranges
        if (hostAddress.startsWith("10.") || 
            hostAddress.startsWith("172.") && 
            Integer.parseInt(hostAddress.split("\\.")[1]) >= 16 && 
            Integer.parseInt(hostAddress.split("\\.")[1]) <= 31 ||
            hostAddress.startsWith("192.168.")) {
            return true;
        }

        return addr.isLoopbackAddress() || 
               addr.isSiteLocalAddress() || 
               addr.isLinkLocalAddress() ||
               addr.isAnyLocalAddress() ||
               addr.isMulticastAddress();
    }
}

